const requestItem = $('開通查詢 Webhook').first().json || {};
const body = requestItem.body || requestItem;
const userId = String(body.userId || body.user_id || body.lineUserId || body.line_user_id || body['LINE userId'] || '').trim();
const displayName = String(body.displayName || body.name || body.operatorName || '').trim();
const operators = $input.all().map((item) => item.json || {});
const requiredFeature = 'OCR補料單';

function getValue(obj, keys) {
  for (const key of keys) {
    if (obj?.[key] !== undefined && obj?.[key] !== null) return obj[key];
  }
  return '';
}

function normalize(value) {
  return String(value || '').trim();
}

function toList(value) {
  if (Array.isArray(value)) return value.map((item) => String(item?.name || item).trim()).filter(Boolean);
  const text = String(value ?? '').trim();
  if (!text) return [];
  try {
    const parsed = JSON.parse(text);
    if (Array.isArray(parsed)) return parsed.map((item) => String(item?.name || item).trim()).filter(Boolean);
  } catch (error) {}
  return text.split(/[,，、]/).map((item) => item.trim()).filter(Boolean);
}

const matched = operators.find((operator) => {
  const allowedUserId = normalize(getValue(operator, [
    'property_LINE userId',
    'LINE userId',
    'property_userId',
    'userId',
    'property_lineUserId',
    'lineUserId'
  ]));
  return userId && allowedUserId === userId;
});

const status = normalize(getValue(matched || {}, ['property_狀態', '狀態']));
const features = toList(getValue(matched || {}, ['property_可使用功能', '可使用功能']));
const allowed = Boolean(matched && status === '已開通' && features.includes(requiredFeature));
const name = normalize(getValue(matched || {}, ['property_名稱', '名稱', 'property_姓名', '姓名', 'property_name', 'name', 'Name', 'title'])) || displayName;
const role = normalize(getValue(matched || {}, ['property_角色', '角色']));

return [{
  json: {
    ok: Boolean(userId),
    allowed,
    userId,
    name,
    displayName,
    role,
    features,
    status: status || '未建立',
    message: userId ? (allowed ? '已開通' : '未開通或未開放 OCR補料單') : '缺少 LINE userId'
  }
}];
